templates.templateContent:
##Create Management VLAN##
vlan ${Management_Vlan_Number}
name $Management_Vlan_Name

##Create Management SVI##
interface vlan${Management_Vlan_Number}
ip address $Mangament_IP_Address $Subnet
no shut

##Configure Upstream Link##
interface $Upstream_Interface
switchport mode trunk
switchport trunk allowed vlan add ${Management_Vlan_Number}

##Configure Default Gateway##
ip default-gateway $Default_Gateway 
## or ip route 0.0.0.0 0.0.0.0 $Default_Gateway


##Change management of switch from PNP Vlan to Management VLAN##
ip http client connection forceclose
ip http client source-interface vlan${Management_Vlan_Number}
ip ssh source-interface vlan${Management_Vlan_Number}
ip domain lookup source-interface vlan${Management_Vlan_Number}

interface vlan${Management_Vlan_Number}
no shut

